import React, { useEffect, useState } from "react";
import { Link, NavLink } from "react-router-dom";
import API from "../api/axios";
import "../style.css";
import heroImage from "../pic/h.jpg";

function HomePage() {
  const [darkMode, setDarkMode] = useState(false);
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  // Fetch posts
  useEffect(() => {
    API.get("/posts")
      .then((res) => setPosts(res.data))
      .finally(() => setLoading(false));
  }, []);

  // Theme toggle
  const toggleTheme = () => {
    setDarkMode(!darkMode);
  };

  // Load saved theme
  useEffect(() => {
    const savedTheme = localStorage.getItem("theme");
    if (savedTheme === "dark") {
      setDarkMode(true);
    }
  }, []);

  // Apply theme
  useEffect(() => {
    if (darkMode) {
      document.body.classList.add("dark-mode");
      localStorage.setItem("theme", "dark");
    } else {
      document.body.classList.remove("dark-mode");
      localStorage.setItem("theme", "light");
    }
  }, [darkMode]);

  if (loading)
    return (
      <p style={{ textAlign: "center", padding: "2rem" }}>Loading posts...</p>
    );

  return (
    <div className="home-wrapper">
      {/* Header */}
      <header>
        <div className="logo">My Passion 💻</div>
        <nav>
          <ul className="nav-menu">
            <li>
              <NavLink
                to="/home"
                className={({ isActive }) => (isActive ? "active" : "")}
              >
                Home
              </NavLink>
            </li>
            <li>
              <NavLink
                to="/about"
                className={({ isActive }) => (isActive ? "active" : "")}
              >
                About
              </NavLink>
            </li>
            <li>
              <NavLink
                to="/contact"
                className={({ isActive }) => (isActive ? "active" : "")}
              >
                Contact
              </NavLink>
            </li>
            <li>
              <NavLink
                to="/register"
                className={({ isActive }) => (isActive ? "active" : "")}
              >
                Register
              </NavLink>
            </li>
          </ul>
        </nav>
      </header>

      {/* Hero Section */}
      <header>
  <div className="logo">My Passion 💻</div>
  <nav>
    <ul className="nav-menu">
      <li><NavLink to="/home">Home</NavLink></li>
      <li><NavLink to="/about">About</NavLink></li>
      <li><NavLink to="/contact">Contact</NavLink></li>
      <li><NavLink to="/register">Register</NavLink></li>
    </ul>
  </nav>
</header>

      {/* Preview Cards */}
      <section className="preview-section">
        <div className="preview-cards">
          <div className="preview-card">
            <h3>📖 About</h3>
            <p>Learn about my coding journey and what inspires me.</p>
            <Link to="/about" className="card-link">
              Read More →
            </Link>
          </div>
          <div className="preview-card">
            <h3>💬 Contact</h3>
            <p>Get in touch and explore useful resources.</p>
            <Link to="/contact" className="card-link">
              Get in Touch →
            </Link>
          </div>
          <div className="preview-card">
            <h3>👥 Join</h3>
            <p>Sign up and become part of our community.</p>
            <Link to="/register" className="card-link">
              Register Now →
            </Link>
          </div>
        </div>
      </section>

      {/* Highlights */}
      <section className="highlights">
        <h2>Key Highlights</h2>
        <ul>
          <li>Highlight 1 about Coding</li>
          <li>Highlight 2 about W3Schools</li>
          <li>Highlight 3 about Stack Overflow</li>
          <li>Highlight 4 about FreeCodeCamp</li>
        </ul>
      </section>

      {/* Latest Posts */}
      <section className="posts-section">
        <h2>Latest Posts</h2>
        {posts.length === 0 ? (
          <p style={{ textAlign: "center", color: "#666", padding: "2rem" }}>
            No posts yet. Be the first to write one!
          </p>
        ) : (
          <div className="posts-grid">
            {posts.map((post) => (
              <Link
                to={`/posts/${post._id}`}
                key={post._id}
                className="post-card-link"
              >
                <div className="post-card">
                  {post.image && (
                    <div className="post-image">
                      <img
                        src={`http://localhost:5000/uploads/${post.image}`}
                        alt={post.title}
                      />
                    </div>
                  )}
                  <div className="post-details">
                    <h3>{post.title}</h3>
                    <p>{post.body.substring(0, 100)}...</p>
                    <small>
                      By {post.author?.name} •{" "}
                      {new Date(post.createdAt).toLocaleDateString()}
                    </small>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </section>

      {/* Theme Toggle */}
      <button className="theme-toggle" onClick={toggleTheme}>
        {darkMode ? "☀️ Light Mode" : "🌙 Dark Mode"}
      </button>

      {/* Footer */}
      <footer>
        <p>Contact: email</p>
      </footer>
    </div>
  );
}

export default HomePage;
